import { vi, describe, it, expect, afterEach } from 'vitest';
import { render, screen, waitFor } from '@testing-library/react';
import { AsyncCounter } from './AsyncCounter';

describe('AsyncCounter', () => {
  afterEach(() => vi.useRealTimers());

  it('increments after delay using fake timers', async () => {
    vi.useFakeTimers();
    render(<AsyncCounter />);

    await vi.runAllTimersAsync(); // drains setTimeout + microtasks
    expect(screen.getByText('Count: 1')).toBeInTheDocument();
  });

  it('finds element after fetch resolves', async () => {
    render(<AsyncCounter />);
    const el = await screen.findByText('Count: 1'); // retries up to 1000ms
    expect(el).toBeInTheDocument();
  });
});

